ant hotels furnas', ARRAY['spa day']::text[], 'Octant Hotels Furnas', ''),('aqua park zakopane', ARRAY['spa day']::text[], 'Aqua Park Zakopane', ''),('thermae bath spa', ARRAY['bath uk','spa day']::text[], 'Thermae Bath Spa', ''),('qc termemilano', ARRAY['spa day']::text[], 'QC Termemilano', ''),('cleopatra antique pools', ARRAY['pamukkale','spa day']::text[], 'Cleopatra Antique Pools', 'The wow factor on the place is the fact that your swimming over centuries old Roman columns and other relics. It’s a bit of a hike to get to, but the pictures for the gram are worth the trip to get there.'),('vichy celestins spa hotel vichy france', ARRAY['spa day']::text[], 'VICHY CÉLESTINS SPA HÔTEL . Vichy - France', ''),('terme merano', ARRAY['spa day']::text[], 'Terme Merano', ''),('aqua sana forest spa nottinghamshire', ARRAY['spa day']::text[], 'Aqua Sana Forest Spa Nottinghamshire', ''),('luxury spa hotel olympic palace', ARRAY['spa day']::text[], 'Luxury Spa Hotel OLYMPIC PALACE', ''),('chocho owskie termy', ARRAY['spa day']::text[], 'Chochołowskie Termy', ''),('termy maltanskie', ARRAY['spa day']::text[], 'Termy Maltańskie', ''),('aquardens', ARRAY['spa day']::text[], 'Aquardens', ''),('lucknam park hotel spa', ARRAY['spa day']::text[], 'Lucknam Park Hotel & Spa', ''),('charcas de aguas termales', ARRAY['spa day']::text[], 'Charcas de aguas termales', ''),('rimini terme', ARRAY['spa day']::text[], 'Rimini Terme', ''),('scandinave spa whistler', ARRAY['spa day']::text[], 'Scandinave Spa Whistler', ''),('center parcs de vossemeren', ARRAY['spa day']::text[], 'Center Parcs De Vossemeren', ''),('cascate del mulino hot spring', ARRAY['spa day']::text[], 'Cascate del Mulino-Hot Spring', ''),('buxton crescent spa', ARRAY['spa day']::text[], 'Buxton Crescent Spa', ''),('hierapark thermal spa hotel deluxe', ARRAY['spa day']::text[], 'Hierapark Thermal & Spa Hotel Deluxe', ''),('qc terme dolomiti', ARRAY['spa day']::text[], 'QC Terme Dolomiti', ''),('caldas de a chavasqueira', ARRAY